const prefs = $input.item.json;
const wb    = $('Webhook').item.json.body;

return [{
  json: {
    user_id:         wb.user_id,
    client_id:       wb.client_id,
    client_email:    wb.client_email,
    report_type:     wb.report_type,
    report_month:    wb.report_month,
    delivery_method: prefs.delivery_method ?? 'email',
    phone_number:    prefs.phone_number    ?? null,
  }
}];

const data     = $('Code — Normalize Data').item.json;
const linkData = $input.item.json;

const expiresAt = new Date();
expiresAt.setMinutes(expiresAt.getMinutes() + 30);

return [{
  json: {
    ...data,
    magic_link:            linkData.url   ?? null,
    magic_link_expires_at: expiresAt.toISOString(),
  }
}];

const d = $('Code — Add Magic Link').item.json;
return [{
  json: {
    client_id:             d.client_id,
    client_email:          d.client_email,
    report_type:           d.report_type,
    report_month:          d.report_month,
    report_url:            d.magic_link,
    magic_link_sent:       true,
    magic_link_expires_at: d.magic_link_expires_at,
    email_sent:            true,
    email_provider:        'mailgun',
    sms_sent:              false,
    status:                'Sent',
    n8n_execution_id:      $execution.id,
  }
}];

const d      = $('Code — Add Magic Link').item.json;
const vonage = $input.item.json;
const msg    = vonage?.messages?.[0];
const ok     = msg?.status === '0';

return [{
  json: {
    client_id:             d.client_id,
    client_email:          d.client_email,
    report_type:           d.report_type,
    report_month:          d.report_month,
    report_url:            d.magic_link,
    magic_link_sent:       true,
    magic_link_expires_at: d.magic_link_expires_at,
    email_sent:            false,
    sms_sent:              ok,
    sms_provider:          'vonage',
    status:                ok ? 'Sent' : 'Failed',
    failure_reason:        ok ? null : (msg?.['error-text'] ?? 'Unknown Vonage error'),
    n8n_execution_id:      $execution.id,
  }
}];
